sys_ux_data_broker_transform.required_translations:
[ {
  "message" : "Approved",
  "comment" : ""
}, {
  "message" : "Email address to send to",
  "comment" : ""
}, {
  "message" : "SysId of the Snapshot record",
  "comment" : ""
}, {
  "message" : "Whether or not the user approves the snapshot. If not it will be deleted.",
  "comment" : ""
} ]

sys_ux_data_broker_transform.script:
function transform({sysId, email, approved}){  
    const snapshotQuery = new global.GlideQuery('x_snc_pb_core_snapshot').where("sys_id", sysId);

	const {db_image : dbImage, request} = snapshotQuery
		.selectOne('db_image', 'request.email', 'request.sys_id')
		.get();

	if(approved === false){
        gs.info("Approved is false, deleting db_image");
        if(dbImage) {
            new global.GlideQuery('db_image')
            .where('sys_id', dbImage)
            .deleteMultiple();
        }

        gs.info("Approved is false, deleting snapshot");
		snapshotQuery.deleteMultiple();
		return;
	} else if(approved === true){
        gs.info("Approved is true, sending email");
        const sendEmail = email || request.email;
        if(!sendEmail){
            const msg = `Unable to send email because no email was passed or found in the request ${request.sys_id}`;
            gs.error(msg);
            throw msg;
        }
        snapshotQuery.update({'send_email' : sendEmail});
        return;
    } else {
        throw "Unknown error in PB Public Send Snapshot--approved must either be explicitly 'true' or 'false'.";
    }
}
